#!/usr/bin/env python3
import sys

def solve():
    data = sys.stdin.read().strip().split()
    if not data:
        return
    it = iter(data)
    T = int(next(it))
    out_lines = []
    for _ in range(T):
        N = int(next(it))
        ans = [0] * (N + 1)
        odds = [i for i in range(1, N + 1, 2)]
        evens = [i for i in range(2, N + 1, 2)]
        for i, pos in enumerate(odds):
            ans[pos] = odds[(i + 1) % len(odds)]
        for i, pos in enumerate(evens):
            ans[pos] = evens[(i + 1) % len(evens)]
        out_lines.append(' '.join(str(ans[i]) for i in range(1, N + 1)))
    sys.stdout.write('\n'.join(out_lines))

if __name__ == "__main__":
    solve()

